    font-size: 11px;
    text-transform: uppercase;
    letter-spacing: 0.06em;
    color: var(--muted);
    white-space: nowrap;
  }

  .users-table td {
    border: 1px solid var(--border);
    padding: 10px 12px;
    background: var(--bg2);
    vertical-align: top;
  }

  .users-table tr:nth-child(even) td {
    background: var(--bg3);
  }

  .users-table tr:hover td {
    background: var(--bg-op);
  }

  .user-id {
    font-size: 11px;
    color: var(--hint);
  }

  .user-name {
    font-weight: 700;
    color: var(--accent);
  }

  .user-pokemon {
    font-size: 12px;
    color: var(--name);
  }

  .user-code {
    font-family: ui-monospace, SFMono-Regular, Menlo, monospace;
    font-size: 12px;
    color: var(--muted);
  }

  @media (prefers-color-scheme: dark) {
    :root {
      --bg: #0f0f11;
      --bg2: #1c1c1e;
      --bg3: #2c2c2e;
      --bg-op: #1a1a1c;
      --bg-post: #1c1c1e;
      --text: #f2f2f7;
      --muted: #98989f;
      --hint: #636366;
      --border: rgba(255, 255, 255, 0.08);
      --border2: rgba(255, 255, 255, 0.14);
      --name: #34c789;
      --link: #5e9cf3;
      --danger: #ff453a;
      --accent: #f2f2f7;
      --success: #30d158;
      --shadow-sm: 0 1px 3px rgba(0, 0, 0, 0.3);
      --shadow-md: 0 6px 20px rgba(0, 0, 0, 0.4);
    }

    .ib-header {
      background: rgba(15, 15, 17, 0.88);
    }
  }

  @media (max-width: 720px) {
    .ib-header-inner {
      min-height: auto;
      padding: 12px 0;
      flex-wrap: wrap;
    }

    .ib-nav-spacer {
      display: none;
    }

    .home-banner,
    .page-header,
    .top-bar,
    .response-header,
    .form-row,
    .btn-row {
      flex-direction: column;
      align-items: stretch;
    }

    .form-label {
      min-width: auto;
      text-align: left;
      padding-top: 0;
    }

    .post-date {
      margin-left: 0;
    }

    .id-input {
      width: 100%;
    }
  }
