import { useState, useEffect, useCallback, useMemo, useRef } from "react";

const DEFAULT_BASE = process.env.REACT_APP_API_BASE || "http://localhost:8189";

const SECTIONS = [
  { name: "/boards", color: "#7F77DD", endpoints: [{ method: "GET", path: "/boards/all" }, { method: "GET", path: "/boards/{id}", hasId: true }, { method: "POST", path: "/boards/create" }] },
  { name: "/posts",  color: "#1D9E75", endpoints: [{ method: "GET", path: "/posts/all" }, { method: "GET", path: "/posts/{id}", hasId: true }, { method: "POST", path: "/posts/create" }] },
  { name: "/threads",color: "#D85A30", endpoints: [{ method: "GET", path: "/threads/all" }, { method: "GET", path: "/threads/{id}", hasId: true }, { method: "POST", path: "/threads/create" }] },
  { name: "/fakers", color: "#BA7517", endpoints: [{ method: "GET", path: "/fakers/generate" }, { method: "GET", path: "/posts/generateFakePost" }, { method: "GET", path: "/boards/generateFakeBoard" }, { method: "GET", path: "/threads/generateFakeThread" }, { method: "GET", path: "/threads/threadFactory" }] },
  { name: "/admin",  color: "#aa1111", endpoints: [{ method: "DELETE", path: "/api/admin/truncate", danger: true }] },
  { name: "/factory", color: "#6a3d9a", endpoints: [
    { method: "POST", path: "/fakers/userFactory",          hasBody: true, bodyField: "users", bodyLabel: "юзеров" },
    { method: "GET",  path: "/boards/boardFactory/{id}",    hasId: true, idLabel: "досок" },
    { method: "GET",  path: "/posts/fillThread/{id}/{count}", hasId: true, idLabel: "thread id", hasId2: true, id2Label: "постов" },
    { method: "GET",  path: "/news/startNewsFactory/{count}", hasId: true, idLabel: "count" }
  ]},
];

// ─── STYLES ──────────────────────────────────────────────────────────────────
const styles = `
  :root {
    --bg: #f5f5f7;
    --bg2: #ffffff;
    --bg3: #ebebed;
    --bg-op: #f9f9fb;
    --bg-post: #ffffff;
    --text: #1c1c1e;
    --muted: #6e6e73;
    --hint: #a0a0a8;
    --border: rgba(0, 0, 0, 0.08);
    --border2: rgba(0, 0, 0, 0.14);
    --name: #1a7a6e;
    --link: #2d6fd4;
    --danger: #c0392b;
    --accent: #1c1c1e;
    --success: #1a7a3c;
    --radius: 10px;
    --radius-lg: 16px;
    --shadow-sm: 0 1px 3px rgba(0, 0, 0, 0.06);
    --shadow-md: 0 6px 20px rgba(0, 0, 0, 0.08);
  }

  * {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
  }

  body {
    font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
    font-size: 14px;
    background: var(--bg);
    color: var(--text);
    min-height: 100vh;
    line-height: 1.5;
  }

  a {
    color: var(--link);
    text-decoration: none;
  }

  a:hover {
    text-decoration: underline;
  }

  /* HEADER */
  .ib-header {
    background: rgba(255,255,255,0.88);
    backdrop-filter: blur(10px);
    border-bottom: 1px solid var(--border);
    padding: 0 1rem;
    position: sticky;
    top: 0;
    z-index: 100;
  }

  .ib-header-inner {
    max-width: 1080px;
    margin: 0 auto;
    display: flex;
    align-items: center;
    gap: 1rem;
    min-height: 60px;
  }

  .ib-logo {
    font-size: 18px;
    font-weight: 800;
    color: var(--accent);
    cursor: pointer;
    white-space: nowrap;
    user-select: none;
    letter-spacing: -0.02em;
  }

  .ib-logo span {
    color: var(--link);
  }

  .ib-breadcrumb {
    display: flex;
    align-items: center;
    gap: 4px;
    font-size: 12px;
    color: var(--muted);
    overflow: hidden;
  }

  .ib-breadcrumb-sep {
    color: var(--hint);
    margin: 0 2px;
  }

  .ib-breadcrumb-link {
    cursor: pointer;
    color: var(--muted);
    white-space: nowrap;
    font-size: 12px;
  }

  .ib-breadcrumb-link:hover {
    color: var(--text);
  }

  .ib-breadcrumb-cur {
    color: var(--text);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    font-size: 12px;
  }

  .ib-nav-spacer {
    flex: 1;
  }

  .ib-nav-tabs {
    display: flex;
    gap: 8px;
  }

  .ib-tab {
    font-family: inherit;
    font-size: 12px;
    font-weight: 600;
    padding: 8px 14px;
    border: 1px solid transparent;
    border-radius: 999px;
    background: transparent;
    color: var(--muted);
    cursor: pointer;
    transition: 0.18s ease;
    white-space: nowrap;
  }

  .ib-tab:hover {
    background: var(--bg3);
    color: var(--text);
  }

  .ib-tab.active {
    background: var(--bg2);
    color: var(--text);
    border-color: var(--border);
    box-shadow: var(--shadow-sm);
  }

  /* LAYOUT */
  .ib-main {
    max-width: 1080px;
    margin: 0 auto;
    padding: 20px 16px 40px;
  }

  /* HOME */
  .home-banner {
    background: linear-gradient(180deg, var(--bg2), var(--bg-op));
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    box-shadow: var(--shadow-sm);
    padding: 16px 18px;
    margin-bottom: 16px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 1rem;
  }

  .home-banner-title {
    font-size: 22px;
    font-weight: 800;
    color: var(--accent);
    letter-spacing: -0.03em;
  }

  .home-banner-sub {
    font-size: 13px;
    color: var(--muted);
    margin-top: 4px;
  }

  .home-banner-tag {
    font-size: 12px;
    padding: 6px 10px;
    border: 1px solid var(--border);
    border-radius: 999px;
    background: var(--bg2);
    color: var(--muted);
    white-space: nowrap;
  }

  .boards-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
    gap: 12px;
  }

  .board-card {
    background: var(--bg2);
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    box-shadow: var(--shadow-sm);
    padding: 14px;
    cursor: pointer;
    transition: transform 0.15s ease, box-shadow 0.15s ease, border-color 0.15s ease;
  }

  .board-card:hover {
    transform: translateY(-1px);
    border-color: var(--border2);
    box-shadow: var(--shadow-md);
  }

  .board-tag {
    font-size: 11px;
    color: var(--hint);
    margin-bottom: 6px;
  }

  .board-name {
    font-size: 14px;
    font-weight: 700;
    color: var(--accent);
    margin-bottom: 4px;
  }

  .board-desc {
    font-size: 12px;
    color: var(--muted);
    line-height: 1.5;
    overflow: hidden;
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
  }

  .board-meta {
    margin-top: 10px;
  }

  .board-stat {
    font-size: 11px;
    color: var(--hint);
  }

  /* PAGE HEADER */
  .page-header {
    background: var(--bg2);
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    box-shadow: var(--shadow-sm);
    padding: 14px 16px;
    margin-bottom: 14px;
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: 1rem;
  }

  .page-title {
    font-size: 20px;
    font-weight: 800;
    color: var(--accent);
    letter-spacing: -0.02em;
  }

  .page-sub {
    font-size: 12px;
    color: var(--muted);
    margin-top: 4px;
  }

  /* THREAD LIST */
  .thread-list {
    display: flex;
    flex-direction: column;
