  );
}

// ─── BOARD PAGE ──────────────────────────────────────────────────────────────
function BoardPage({ api, board, onThread, baseUrl }) {
  const [threads, setThreads] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);

  const load = useCallback((p = 1) => {
    setLoading(true); setError(null);
    api.get(`/threads/getThreadsInBoard/${board.id}?page=${p - 1}&limit=20`)
      .then(r => {
        setThreads(normalizeList(r));
        const pagination = r?.payload?.pagination ?? r?.pagination ?? null;
        if (pagination) setTotalPages(pagination.pages ?? 1);
        setPage(p);
      })
      .catch(e => setError(e.message))
      .finally(() => setLoading(false));
  }, [api, board]);

  useEffect(() => { load(1); }, [load]);

  return (
    <div className="ib-main">
      <div className="page-header">
        <div>
          <div className="page-title">/{getBoardName(board).toLowerCase()}/</div>
          {getBoardDesc(board) && <div className="page-sub">{getBoardDesc(board)}</div>}
        </div>
        <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
          {threads && <span className="count-pill">{threads.length} тредов</span>}
          <button className="clear-btn" onClick={() => load(page)} disabled={loading} title="Обновить">↻</button>
        </div>
      </div>

      {/* Форма создания треда */}
      <CreateThreadForm api={api} boardId={board.id} onCreated={load} baseUrl={baseUrl} />

      <div className="section-label">треды</div>
      {loading && <LoadingBlock />}
      {error && <ErrorBlock msg={error} />}
      {!loading && !error && threads?.length === 0 && <EmptyBlock text="нет тредов" />}
      {!loading && !error && threads?.length > 0 && (
        <>
          <div className="thread-list">
            {threads.map((t, i) => (
              <div className="thread-card" key={t.id ?? i} onClick={() => onThread(t)}>
                <div className="thread-num">#{(page - 1) * 20 + i + 1}</div>
                {getImgUrl(t) && (
                  <img
                    src={getImgUrl(t)}
                    alt="thread"
                    style={{ width: 56, height: 56, objectFit: "cover", border: "1px solid var(--border)", flexShrink: 0 }}
                    onError={(e) => { e.target.style.display = "none"; }}
                    onClick={(e) => { e.stopPropagation(); window.open(getImgUrl(t), "_blank"); }}
                  />
                )}
                <div className="thread-body">
                  <div className="thread-title">{getThreadTitle(t)}</div>
                  {getThreadPreview(t) && <div className="thread-preview">{getThreadPreview(t)}</div>}
                </div>
                <div className="thread-arrow">›</div>
              </div>
            ))}
          </div>
          {totalPages > 1 && (
            <div style={{ display: "flex", gap: 4, marginTop: 12, alignItems: "center", flexWrap: "wrap" }}>
              <button className="form-btn" onClick={() => load(page - 1)} disabled={page <= 1 || loading}>← пред</button>
              {Array.from({ length: totalPages }, (_, i) => i + 1).map(n => (
                <button
                  key={n}
                  className={`form-btn${n === page ? " primary" : ""}`}
                  onClick={() => load(n)}
                  disabled={loading}
                  style={{ minWidth: 32 }}
                >{n}</button>
              ))}
              <button className="form-btn" onClick={() => load(page + 1)} disabled={page >= totalPages || loading}>след →</button>
            </div>
          )}
        </>
      )}
    </div>
  );
}

// ─── THREAD PAGE ─────────────────────────────────────────────────────────────
function ThreadPage({ api, thread, baseUrl }) {
  const [posts, setPosts] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [replyTo, setReplyTo] = useState(null);
  const [highlightId, setHighlightId] = useState(null);
  const postRefs = useRef({});

  const load = useCallback((p = 1) => {
    setLoading(true); setError(null);
    api.get(`/posts/getPostsInThread/${thread.id}?page=${p - 1}&limit=20`)
      .then(r => {
        const list = normalizeList(r);
        setPosts(list);
        // читаем пагинацию из ответа
        const pagination = r?.payload?.pagination ?? r?.pagination ?? null;
        if (pagination) {
          setTotalPages(pagination.pages ?? 1);
        }
        setPage(p);
      })
      .catch(e => setError(e.message))
      .finally(() => setLoading(false));
  }, [api, thread]);

  useEffect(() => { load(1); }, [load]);

  const scrollToPost = (id) => {
    const el = postRefs.current[id];
    if (el) {
      el.scrollIntoView({ behavior: "smooth", block: "center" });
      setHighlightId(id);
      setTimeout(() => setHighlightId(null), 1500);
    }
  };

  const replyToPost = posts?.find(p => p.id === replyTo) ?? null;

  return (
    <div className="ib-main">
      <div className="page-header">
        <div>
          <div className="page-title">{getThreadTitle(thread)}</div>
          {getThreadPreview(thread) && <div className="page-sub">{getThreadPreview(thread)}</div>}
        </div>
        <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
          {posts && <span className="count-pill">{posts.length} постов</span>}
          <button className="clear-btn" onClick={() => load(page)} disabled={loading} title="Обновить">↻</button>
        </div>
      </div>

      <ReplyForm
        api={api}
        threadId={thread.id}
        replyTo={replyTo}
        replyToPost={replyToPost}
        onClearReply={() => setReplyTo(null)}
        onCreated={() => load(page)}
        baseUrl={baseUrl}
      />

      <div className="section-label">посты</div>
      {loading && <LoadingBlock />}
      {error && <ErrorBlock msg={error} />}
      {!loading && !error && posts?.length === 0 && <EmptyBlock text="нет постов" />}
      {!loading && !error && posts?.length > 0 && (
        <>
          <div className="post-list">
            {posts.map((p, i) => (
              <div
                className={`post-card${highlightId === p.id ? " reply-target" : ""}`}
                key={p.id ?? i}
                ref={el => { if (el && p.id) postRefs.current[p.id] = el; }}
              >
                <div className="post-head">
                  <span className="post-author">{getAuthor(p)}</span>
                  <span className="post-no" onClick={() => scrollToPost(p.id)}>No.{p.id ?? i + 1}</span>
                  {(p.createdAt || p.created_at || p.date || p.timestamp) && (
                    <span className="post-date">
                      {formatDate(p.createdAt ?? p.created_at ?? p.date ?? p.timestamp)}
                    </span>
                  )}
                  <button className="post-reply-btn" onClick={() => setReplyTo(p.id)}>[Ответить]</button>
                </div>
                <PostBody text={getPostBody(p) || "(пустой пост)"} posts={posts} onQuoteClick={scrollToPost} />
                {getImgUrl(p) && (
                  <img
                    className="post-image"
                    src={getImgUrl(p)}
                    alt="post attachment"
                    onClick={() => window.open(getImgUrl(p), "_blank")}
                    onError={(e) => { e.target.style.display = "none"; }}
                  />
                )}
              </div>
            ))}
          </div>

          {/* Пагинация */}
          {totalPages > 1 && (
            <div style={{ display: "flex", gap: 4, marginTop: 12, alignItems: "center", flexWrap: "wrap" }}>
              <button
                className="form-btn"
                onClick={() => load(page - 1)}
                disabled={page <= 1 || loading}
              >← пред</button>
              {Array.from({ length: totalPages }, (_, i) => i + 1).map(n => (
                <button
                  key={n}
                  className={`form-btn${n === page ? " primary" : ""}`}
                  onClick={() => load(n)}
                  disabled={loading}
                  style={{ minWidth: 32 }}
                >{n}</button>
              ))}
              <button
                className="form-btn"
                onClick={() => load(page + 1)}
                disabled={page >= totalPages || loading}
              >след →</button>
            </div>
          )}
        </>
      )}
    </div>
  );
}

// ─── USERS PAGE ──────────────────────────────────────────────────────────────
function UsersPage({ api }) {
  const [users, setUsers] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [total, setTotal] = useState(0);
  const [search, setSearch] = useState("");

  const load = useCallback((p = 1) => {
    setLoading(true); setError(null);
    api.get(`/fakers/all?page=${p - 1}&limit=20`)
      .then(r => {
        setUsers(normalizeList(r));
        const pagination = r?.payload?.pagination ?? r?.pagination ?? null;
        if (pagination) {
          setTotalPages(pagination.pages ?? 1);
          setTotal(pagination.total ?? 0);
        }
        setPage(p);
      })
      .catch(e => setError(e.message))
      .finally(() => setLoading(false));
  }, [api]);

  useEffect(() => { load(1); }, [load]);

  const filtered = users?.filter(u => {
    if (!search.trim()) return true;
    const q = search.toLowerCase();
    return (
      String(u.id).includes(q) ||
      u.name?.toLowerCase().includes(q) ||
      u.lastName?.toLowerCase().includes(q) ||
      u.pokemon?.toLowerCase().includes(q) ||
      u.phoneNumber?.toLowerCase().includes(q) ||
      u.code?.includes(q)
    );
  }) ?? [];

  return (
    <div className="ib-main">
      <div className="page-header">
        <div>
          <div className="page-title">// users</div>
          <div className="page-sub">датасет пользователей</div>
        </div>
        <span className="count-pill">{total} записей</span>
      </div>

      {/* Поиск по странице */}
      <div style={{ marginBottom: 10 }}>
        <input
          className="base-input"
          style={{ maxWidth: 320, fontSize: 12, padding: "5px 8px" }}
          value={search}
          onChange={e => setSearch(e.target.value)}
          placeholder="Поиск по имени, покемону, коду..."
        />
      </div>

      {loading && <LoadingBlock />}
      {error && <ErrorBlock msg={error} />}
      {!loading && !error && filtered.length === 0 && <EmptyBlock text="нет пользователей" />}
      {!loading && !error && filtered.length > 0 && (
        <>
          <div style={{ overflowX: "auto" }}>
            <table className="users-table">
              <thead>
                <tr>
                  <th>ID</th>
                  <th>Имя</th>
                  <th>Фамилия</th>
                  <th>Возраст</th>
                  <th>Телефон</th>
                  <th>Код</th>
                  <th>Покемон</th>
                </tr>
              </thead>
              <tbody>
                {filtered.map((u, i) => (
                  <tr key={u.id ?? i}>
                    <td><span className="user-id">#{u.id}</span></td>
                    <td><span className="user-name">{u.name}</span></td>
                    <td>{u.lastName}</td>
                    <td style={{ textAlign: "center" }}>{u.age}</td>
                    <td>{u.phoneNumber}</td>
                    <td><span className="user-code">{u.code}</span></td>
                    <td><span className="user-pokemon">{u.pokemon}</span></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {/* Пагинация */}
          {totalPages > 1 && (
            <div style={{ display: "flex", gap: 4, marginTop: 12, alignItems: "center", flexWrap: "wrap" }}>
              <button className="form-btn" onClick={() => load(page - 1)} disabled={page <= 1 || loading}>← пред</button>
              {Array.from({ length: Math.min(totalPages, 20) }, (_, i) => i + 1).map(n => (
                <button
                  key={n}
                  className={`form-btn${n === page ? " primary" : ""}`}
                  onClick={() => load(n)}
                  disabled={loading}
                  style={{ minWidth: 32 }}
                >{n}</button>
              ))}
              {totalPages > 20 && <span style={{ fontSize: 11, color: "var(--hint)" }}>...{totalPages}</span>}
              <button className="form-btn" onClick={() => load(page + 1)} disabled={page >= totalPages || loading}>след →</button>
            </div>
          )}
        </>
      )}
    </div>
  );
}

// ─── ADMIN PANEL ─────────────────────────────────────────────────────────────
function AdminPanel({ baseUrl, setBaseUrl }) {
  const [ids, setIds] = useState({});
  const [response, setResponse] = useState(null);
  const [loading, setLoading] = useState(false);
  const [lastReq, setLastReq] = useState("");

  const handleRequest = async (method, pathTemplate, sectionName, danger = false, bodyField = null) => {
    if (danger && !window.confirm(`⚠ Вы уверены? Это действие необратимо!\n\n${method} ${pathTemplate}`)) return;
    let path = pathTemplate;
    if (path.includes("{id}")) {
      const id = ids[sectionName] || "";
      if (!id.trim()) { alert("Введите ID"); return; }
      path = path.replace("{id}", id.trim());
    }
    if (path.includes("{count}")) {
      // paths with both {id} and {count} store count in sectionName + "_count";
      // paths with only {count} (no {id}) store it in sectionName (the primary input)
      const countKey = pathTemplate.includes("{id}") ? sectionName + "_count" : sectionName;
      const count = ids[countKey] || "";
      if (!count.trim()) { alert("Введите кол-во"); setLoading(false); return; }
      path = path.replace("{count}", count.trim());
    }
    const url = baseUrl.replace(/\/$/, "") + path;
    setLastReq(`${method} ${url}`);
    setLoading(true); setResponse(null);
    try {
      const opts = { method, headers: { "Content-Type": "application/json" } };
      if (method === "POST") {
        // если есть bodyField — берём из ids, иначе пустой объект
        if (bodyField) {
          const val = ids[sectionName + "_body"] || "";
          if (!val.trim()) { alert("Введите значение"); setLoading(false); return; }
          opts.body = JSON.stringify({ [bodyField]: Number(val) });
        } else {
          opts.body = "{}";
        }
      }
      const res = await fetch(url, opts);
      const ct = res.headers.get("content-type") || "";
      let body;
      if (ct.includes("json")) { const json = await res.json(); body = JSON.stringify(json, null, 2); }
      else { body = await res.text(); }
      setResponse({ status: res.status, ok: res.ok, body: body || "(пустой ответ)" });
    } catch (e) {
      setResponse({ status: "error", ok: false, body: "Ошибка: " + e.message });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="app">
      <div className="top-bar">
        <span className="badge badge-get">BASE URL</span>
        <input className="base-input" value={baseUrl} onChange={e => setBaseUrl(e.target.value)} placeholder="http://localhost:8080" />
      </div>
      <div className="sections">
        {SECTIONS.map(section => (
          <div className="section" key={section.name}>
            <div className="section-title">
              <span className="dot" style={{ background: section.color }} />
              {section.name}
            </div>
            {section.endpoints.map(ep => (
              <div className="btn-row" key={ep.path}>
                <span className={`badge ${ep.method === "GET" ? "badge-get" : ep.method === "POST" && ep.hasBody ? "badge-factory" : ep.method === "POST" ? "badge-post" : "badge-delete"}`}>{ep.method}</span>
                <button
                  className={`endpoint-btn${ep.danger ? " danger" : ""}`}
                  onClick={() => handleRequest(ep.method, ep.path, section.name, ep.danger, ep.bodyField ?? null)}
                >{ep.path}</button>
                {ep.hasId && (
                  <input className="id-input" placeholder={ep.idLabel ?? "id"} value={ids[section.name] || ""} onChange={e => setIds(prev => ({ ...prev, [section.name]: e.target.value }))} />
                )}
                {ep.hasId2 && (
                  <input
                    className="id-input"
                    placeholder={ep.id2Label ?? "count"}
                    type="number"
                    min="1"
                    value={ids[section.name + "_count"] || ""}
                    onChange={e => setIds(prev => ({ ...prev, [section.name + "_count"]: e.target.value }))}
                  />
                )}
                {ep.hasBody && (
                  <input
                    className="id-input"
                    style={{ width: 52 }}
                    placeholder={ep.bodyLabel ?? "кол-во"}
                    type="number"
                    min="1"
                    value={ids[section.name + "_body"] || ""}
                    onChange={e => setIds(prev => ({ ...prev, [section.name + "_body"]: e.target.value }))}
                  />
                )}
              </div>
            ))}
          </div>
        ))}
      </div>
      <div className="response-area">
        <div className="response-header">
          <span className="response-label">response</span>
          <div style={{ display: "flex", gap: 6, alignItems: "center" }}>
            {response && <span className={`status-pill ${response.ok ? "status-ok" : "status-err"}`}>{response.status}</span>}
            {!response && !loading && <span className="status-pill status-idle">idle</span>}
            {loading && <span className="status-pill status-idle">...</span>}
            <button className="clear-btn" onClick={() => { setResponse(null); setLastReq(""); }}>clear</button>
          </div>
        </div>
        {lastReq && <div className="req-line">{lastReq}</div>}
        <pre className="response-body" style={{ color: loading ? "var(--hint)" : response?.ok === false ? "var(--danger)" : "var(--text)" }}>
          {loading ? "загрузка..." : response?.body ?? "нажми кнопку чтобы отправить запрос..."}
        </pre>
      </div>
    </div>
  );
}

// ─── ROOT APP ─────────────────────────────────────────────────────────────────
export default function App() {
  const [baseUrl, setBaseUrl] = useState(DEFAULT_BASE);
  const [view, setView] = useState("home");
  const [currentBoard, setCurrentBoard] = useState(null);
  const [currentThread, setCurrentThread] = useState(null);

  const { get, post } = useApi(baseUrl);
  const api = useMemo(() => ({ get, post }), [get, post]);

  const goHome = () => { setView("home"); setCurrentBoard(null); setCurrentThread(null); };
  const goBoard = (b) => { setCurrentBoard(b); setCurrentThread(null); setView("board"); };
  const goThread = (t, board = null) => { if (board) setCurrentBoard(board); setCurrentThread(t); setView("thread"); };

  const crumbs = [];
  if (view !== "home" && view !== "admin") crumbs.push({ label: "home", action: goHome });
  if ((view === "board" || view === "thread") && currentBoard)
    crumbs.push({ label: `/${getBoardName(currentBoard).toLowerCase()}/`, action: () => goBoard(currentBoard) });
  if (view === "thread" && currentThread)
    crumbs.push({ label: getThreadTitle(currentThread), action: null });

  return (
    <>
      <style>{styles}</style>
      <div className="ib-header">
        <div className="ib-header-inner">
          <div className="ib-logo" onClick={goHome}>//<span>img</span>board</div>
          {crumbs.length > 0 && (
            <div className="ib-breadcrumb">
              {crumbs.map((c, i) => (
                <span key={i} style={{ display: "flex", alignItems: "center", gap: 4, minWidth: 0 }}>
                  {i > 0 && <span className="ib-breadcrumb-sep">›</span>}
                  {c.action
                    ? <span className="ib-breadcrumb-link" onClick={c.action}>{c.label}</span>
                    : <span className="ib-breadcrumb-cur">{c.label}</span>}
                </span>
              ))}
            </div>
          )}
          <div className="ib-nav-spacer" />
          <div className="ib-nav-tabs">
            <button className={`ib-tab ${view === "home" ? "active" : ""}`} onClick={goHome}>boards</button>
            <button className={`ib-tab ${view === "users" ? "active" : ""}`} onClick={() => setView("users")}>users</button>
            <button className={`ib-tab ${view === "admin" ? "active" : ""}`} onClick={() => setView("admin")}>admin</button>
          </div>
        </div>
      </div>

      {view === "home"   && <HomePage   api={api} onBoard={goBoard} onThread={goThread} />}
      {view === "board"  && currentBoard  && <BoardPage  api={api} board={currentBoard}   onThread={goThread} baseUrl={baseUrl} />}
      {view === "thread" && currentThread && <ThreadPage api={api} thread={currentThread} baseUrl={baseUrl} />}
      {view === "users"  && <UsersPage   api={api} />}
      {view === "admin"  && <AdminPanel baseUrl={baseUrl} setBaseUrl={setBaseUrl} />}
    </>
  );
}
